2933,0.00836471,0.05637524,0.04115280,-0.04405924,0.01424146,0.03781263,0.01457386,0.04439644,-0.02985129,0.09056098,-0.09487298,0.04838933,-0.14909057,0.04928841,-0.01323428,0.01051843,-0.04062507,-0.05830074,0.01814340,-0.01536612,-0.03563795,0.05629555,0.00729224,-0.04678076,-0.06308681,0.00718905,0.03586864,0.02336193,-0.06617968,-0.03788267,-0.02016304,0.03928301,0.03141339,-0.01375807,-0.02453660,-0.09988479,0.03640823,-0.01608306,-0.00580849,0.07149822,-0.01473885,0.00847844]',E'Group Handlers\n\nGroup handlers can act as routing paths but must call `Next` to continue the flow.\n\n```go\nfunc main() {\n    app := fiber.New()\n\n    handler := func(c fiber.Ctx) error {\n        return c.SendStatus(fiber.StatusOK)\n    }\n    api := app.Group("/api") // /api\n\n    v1 := api.Group("/v1", func(c fiber.Ctx) error { // middleware for /api/v1\n        c.Set("Version", "v1")\n        return c.Next()\n    })\n    v1.Get("/list", handler) // /api/v1/list\n    v1.Get("/user", handler) // /api/v1/user\n\n    log.Fatal(app.Listen(":3000"))\n}\n```','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "Grouping", "section_title": "grouping", "url": "https://github.com/gofiber/fiber/blob/main/docs/guide/grouping.md", "topics": "fiber,http,grouping", "categories": "web,go,rest"}');
