4,0.13758191,0.02192877,0.00502711,0.03620058,0.00748228,0.01604210,0.05428707,-0.01790623,0.03374324,-0.00088870,0.02046173,-0.04983283,0.06510354,-0.10081914,-0.01182372,-0.01113887,-0.00627821,-0.09595584,-0.02081959,0.05028016,-0.05194059,-0.02401125,0.08138416,-0.02613755,-0.02123634,-0.04210631,-0.05728051,0.06099132,0.03188591,0.00729726,0.02751113,-0.01563421,-0.00373125,0.00718729,0.00770832,-0.01904098,-0.06055979,0.04377737,0.01648046,-0.00625187,0.07892232,0.01189260,0.02615369]',E'Catching Errors\n\nimport (\n    "log"\n\n    "github.com/gofiber/fiber/v3"\n    "github.com/gofiber/fiber/v3/middleware/recover"\n)\n\nfunc main() {\n    app := fiber.New()\n\n    app.Use(recover.New())\n\n    app.Get("/", func(c fiber.Ctx) error {\n        panic("This panic is caught by fiber")\n    })\n\n    log.Fatal(app.Listen(":3000"))\n}\n```\n\nUse `fiber.NewError()` to create an error with a status code. If you omit the message, Fiber uses the standard status text (for example, `404` becomes `Not Found`).','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "Error Handling", "section_title": "error-handling", "url": "https://github.com/gofiber/fiber/blob/main/docs/guide/error-handling.md", "topics": "fiber,http,error,handling", "categories": "web,go,rest"}');
