0.00951011,0.01243743,0.00471063,-0.02789410,0.00234276,0.06557439,-0.00084349,0.05342684,0.01866908,0.01754385,-0.06263477,0.05492403,-0.14283814,-0.00466348,-0.05832072,-0.00848511,-0.06561366,-0.00743111,0.03283972,-0.02338517,-0.02946569,0.07981741,-0.01015829,-0.00768954,-0.05273170,-0.01026321,0.02795299,0.01515927,-0.04019298,-0.00238165,0.03343360,-0.02263473,-0.00460430,0.04798601,-0.01366599,-0.10613830,-0.01671301,0.02252167,-0.01367269,0.03037303,0.02653421,0.01331607]',E'Default Error Handler\n\nFiber ships with a default error handler that sends **500 Internal Server Error** for generic errors. If the error is a [fiber.Error](https://godoc.org/github.com/gofiber/fiber#Error), the response uses the embedded status code and message.\n\n```go title="Example"\n// Default error handler\nvar DefaultErrorHandler = func(c fiber.Ctx, err error) error {\n    // Status code defaults to 500\n    code := fiber.StatusInternalServerError\n    var e *fiber.Error\n    matched := errors.As(err, &e)\n    if matched && e != nil {\n        code = e.Code\n    }\n    message := http.StatusText(code)\n    if err != nil && !(matched && e == nil) {\n        message = err.Error()\n    }\n\n    // Set Content-Type: text/plain; charset=utf-8\n    c.Set(fiber.HeaderContentType, fiber.MIMETextPlainCharsetUTF8)\n\n    // Return status code with error message\n    return c.Status(code).SendString(message)\n}\n```','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "Error Handling", "section_title": "error-handling", "url": "https://github.com/gofiber/fiber/blob/main/docs/guide/error-handling.md", "topics": "fiber,http,error,handling", "categories": "web,go,rest"}');
