43,0.14338417,-0.01689127,0.02903569,0.04992257,-0.04411135,-0.01861040,0.09516653,-0.01322754,0.06476057,-0.00158710,0.03724627,-0.06711478,0.03914879,-0.12331939,0.03917428,-0.03770758,-0.02899172,-0.05740405,-0.02051664,0.03820999,-0.03616565,-0.04015302,0.06791396,-0.02396833,-0.01823121,-0.02554472,-0.04082159,0.00001161,0.01676662,-0.01110130,-0.03019115,0.00623056,0.00603785,-0.00549841,0.07314885,-0.01806303,-0.08271727,-0.02735427,-0.01116809,-0.02939722,0.05688678,-0.02139008,0.00358845]',E'Custom Error Handler\n\n```go title="Example"\n// Create a new fiber instance with custom config\napp := fiber.New(fiber.Config{\n    // Override default error handler\n    ErrorHandler: func(ctx fiber.Ctx, err error) error {\n        // Status code defaults to 500\n        code := fiber.StatusInternalServerError\n\n        // Retrieve the custom status code if it''s a *fiber.Error\n        var e *fiber.Error\n        if errors.As(err, &e) && e != nil {\n            code = e.Code\n        }','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "Error Handling", "section_title": "error-handling", "url": "https://github.com/gofiber/fiber/blob/main/docs/guide/error-handling.md", "topics": "fiber,http,error,handling", "categories": "web,go,rest"}');
