9,0.12919043,0.00726139,0.00037056,0.04926128,0.02794879,0.04898404,0.06546512,0.06155622,-0.00367168,-0.01395509,0.11141395,-0.03293964,0.02884773,-0.04882617,0.05069916,0.02355479,0.02912633,-0.01491571,0.02666983,-0.04164609,-0.01177695,-0.02521048,0.01077100,-0.05823762,0.02961578,0.01126955,-0.04131851,-0.02499352,-0.00043803,0.02471692,-0.02142630,-0.08955931,0.00498598,0.04939713,0.05107126,-0.06636789,-0.08704224,0.03752039,0.06622192,0.02693954,0.03349182,0.05498190,0.01880804]',E'SaveFileToStorage\n\nMethod is used to save **any** multipart file to an external storage system.\n\n```go title="Signature"\nfunc (c fiber.Ctx) SaveFileToStorage(fileheader *multipart.FileHeader, path string, storage Storage) error\n```\n\n```go title="Example"\nstorage := memory.New()\n\napp.Post("/", func(c fiber.Ctx) error {\n  // Parse the multipart form:\n  if form, err := c.MultipartForm(); err == nil {\n    // => *multipart.Form\n\n    // Get all files from "documents" key:\n    files := form.File["documents"]\n    // => []*multipart.FileHeader\n\n    // Loop through files:\n    for _, file := range files {\n      fmt.Println(file.Filename, file.Size, file.Header["Content-Type"][0])\n      // => "tutorial.pdf" 360641 "application/pdf"\n\n      // Save the files to storage:\n      if err := c.SaveFileToStorage(file, fmt.Sprintf("./%s", file.Filename), storage); err != nil {\n        return err\n      }\n    }\n    return err\n  }\n})\n```','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "Ctx", "section_title": "ctx", "url": "https://github.com/gofiber/fiber/blob/main/docs/api/ctx.md", "topics": "fiber,http,ctx", "categories": "web,go,rest"}');
