5928,-0.01946637,0.02468826,0.05444235,-0.04343267,0.01308292,0.03707438,0.05061473,0.01519335,-0.04603515,0.11551961,-0.07977812,0.04413938,-0.09042358,0.05153884,-0.08523669,-0.01243440,-0.02768745,-0.04642478,0.00240319,-0.03694895,-0.02972362,0.06172089,-0.05490687,-0.00371291,-0.03884379,-0.03629711,0.02172037,0.01742820,-0.01359662,-0.09151087,0.00304049,0.02656551,0.03573435,-0.00525685,-0.03547905,-0.06863052,0.02287969,-0.06322837,0.00369469,0.04409207,0.00897098,0.05329211]',E'Group\n\nYou can group routes by creating a `*Group` struct.\n\n```go title="Signature"\nfunc (app *App) Group(prefix string, handlers ...any) Router\n```\n\n```go title="Example"\npackage main\n\nimport (\n    "log"\n\n    "github.com/gofiber/fiber/v3"\n)\n\nfunc main() {\n    app := fiber.New()\n\n    api := app.Group("/api", handler)  // /api\n\n    v1 := api.Group("/v1", handler)    // /api/v1\n    v1.Get("/list", handler)           // /api/v1/list\n    v1.Get("/user", handler)           // /api/v1/user\n\n    v2 := api.Group("/v2", handler)    // /api/v2\n    v2.Get("/list", handler)           // /api/v2/list\n    v2.Get("/user", handler)           // /api/v2/user\n\n    log.Fatal(app.Listen(":3000"))\n}\n\nfunc handler(c fiber.Ctx) error {\n    return c.SendString("Handler response")\n}\n```','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "App", "section_title": "app", "url": "https://github.com/gofiber/fiber/blob/main/docs/api/app.md", "topics": "fiber,http,app", "categories": "web,go,rest"}');
