9066,-0.02396526,0.00873602,0.05832941,-0.04963316,0.01920915,0.10758422,0.06528437,0.03881079,-0.02552800,0.08830786,-0.03127321,0.02389561,-0.10809087,0.00450360,-0.05123919,-0.03468144,-0.01815570,-0.01847358,0.00228906,-0.03575104,0.00198527,0.04745977,-0.04980587,0.01049389,-0.00164326,-0.06598043,0.03433663,-0.00301825,0.02425395,-0.03087870,-0.02074855,0.00502534,0.03784317,0.08853406,-0.04425338,0.00609590,0.03341716,-0.00770836,-0.02297696,0.04022503,-0.01993706,0.06421293]',E'NewWithCustomCtx\n\n`NewWithCustomCtx` creates a new `*App` and sets the custom context factory\nfunction at construction time.\n\n```go title="Signature"\nfunc NewWithCustomCtx(fn func(app *App) CustomCtx, config ...Config) *App\n```\n\n```go title="Example"\npackage main\n\nimport (\n    "log"\n\n    "github.com/gofiber/fiber/v3"\n)\n\ntype CustomCtx struct {\n    fiber.DefaultCtx\n}\n\nfunc (c *CustomCtx) Params(key string, defaultValue ...string) string {\n    return "prefix_" + c.DefaultCtx.Params(key)\n}\n\nfunc main() {\n    app := fiber.NewWithCustomCtx(func(app *fiber.App) fiber.CustomCtx {\n        return &CustomCtx{\n            DefaultCtx: *fiber.NewDefaultCtx(app),\n        }\n    })\n\n    app.Get("/:id", func(c fiber.Ctx) error {\n        return c.SendString(c.Params("id"))\n    })\n\n    log.Fatal(app.Listen(":3000"))\n}\n```','{"source": "go-fiber", "version": "3.3", "language": "go", "title": "App", "section_title": "app", "url": "https://github.com/gofiber/fiber/blob/main/docs/api/app.md", "topics": "fiber,http,app", "categories": "web,go,rest"}');
